def knightProbability(n, k, row, column):
    dp = [[0]*n for _ in range(n)]; dp[row][column] = 1
    for _ in range(k):
        new = [[0]*n for _ in range(n)]
        for r in range(n):
            for c in range(n):
                for dr, dc in [(2,1),(2,-1),(-2,1),(-2,-1),(1,2),(1,-2),(-1,2),(-1,-2)]:
                    nr, nc = r+dr, c+dc
                    if 0<=nr<n and 0<=nc<n: new[nr][nc] += dp[r][c]/8.0
        dp = new
    return sum(map(sum, dp))

